// Replay Attack Prevention: Sliding Window Check (+/- 5 minutes)
const requestTime = new Date($json.body.timestamp).getTime();
const now = new Date().getTime();
const windowMs = 5 * 60 * 1000;

if (!requestTime || Math.abs(now - requestTime) > windowMs) {
    throw new Error("Security Alert: Replay attack detected or clock skew too high. Request rejected.");
}

return $json;

// Extract company data from enrichment API
const enrichedData = $input.first().json;

return {
  lead_id: $node["Webhook Trigger"].json.body.lead_id,
  company_size: enrichedData.company_size || 'Unknown',
  industry: enrichedData.industry || 'Not specified',
  linkedin: enrichedData.linkedin_url || '',
  twitter: enrichedData.twitter_handle || '',
  website: enrichedData.website || '',
  revenue_range: enrichedData.revenue_range || 'Unknown',
  location: enrichedData.location || 'Unknown',
  employee_count: enrichedData.employee_count || 0,
  technologies: enrichedData.technologies || [],
  enrichment_score: enrichedData.confidence_score || 0
};

// Lead Scoring Engine Logic
const data = $input.first().json;
let score = 0;

// 1. Company Size Scoring
const empCount = data.employee_count || 0;
if (empCount > 5000) score += 40;
else if (empCount > 1000) score += 30;
else if (empCount > 200) score += 20;
else if (empCount > 50) score += 10;

// 2. Revenue Scoring
const revenue = data.revenue_range || '';
if (revenue.includes('Billion')) score += 50;
else if (revenue.includes('Million')) score += 25;

// 3. Tech Stack Scoring
const techs = data.technologies || [];
if (techs.includes('aws')) score += 15;
if (techs.includes('react')) score += 10;

// 4. Enrichment Confidence
score += (data.enrichment_score * 10);

return {
    ...data,
    lead_score: Math.round(Math.min(score, 100))
};
